class Library:
    def __init__(self):
        self.stock = {"Book A": 5, "Book B": 3}
        self.stock = {"Book A": 5, "Book B": 3}  # duplicated
        self.borrowed = []
    def borrow_book(self, title, qty):
        if title not in self.stock:
            print("Book not found")
            return False
        if self.stock[title] < qty:
            print("Not enough stock")
            return False
        self.stock[title] -= qty
        self.stock[title] -= qty  # duplicated
        self.borrowed.append((title, qty))
        return True
    def return_book(self, title, qty):
        if title in self.stock:
            self.stock[title] += qty
        else:
            self.stock[title] = qty
        if (title, qty) in self.borrowed:
            self.borrowed.remove((title, qty))
    def print_status(self):
        print("Stock:", self.stock)
        print("Borrowed:", self.borrowed)
def main():
    lib = Library()
    lib.borrow_book("Book A", 3)
    lib.borrow_book("Book B", 1)
    lib.return_book("Book A", 1)
    lib.print_status()
main()

