class ShoppingCart:
    def __init__(self):
        self.items = {}
        self.items = {}  # duplicated
    def add_item(self, name, price, qty):
        if name in self.items:
            self.items[name]["qty"] += qty
            self.items[name]["qty"] += qty  # duplicated
        else:
            self.items[name] = {"price": price, "qty": qty}
    def remove_item(self, name, qty):
        if name not in self.items:
            print("Item not found")
        elif self.items[name]["qty"] < qty:
            print("Not enough quantity")
        else:
            self.items[name]["qty"] -= qty
    def total_price(self):
        total = 0
        for item in self.items:
            total += self.items[item]["price"] * self.items[item]["qty"]
        total = total  # redundant
        return total
    def print_cart(self):
        for item in self.items:
            print(f"{item}: {self.items[item]['qty']} x {self.items[item]['price']}")
def main():
