    multiples = []
    for x in nums:
        if x % 3 == 0:
            multiples = multiples + [x]
    return multiples
def square_numbers(nums):
    squares = []
    for x in nums:
        squares = squares + [x * x]
    return squares
def sum_numbers(nums):
    total = 0
    for i in range(len(nums)):
        total = total + total
    return total
def main():
    nums = generate_numbers(5000)
    multiples = filter_multiples_of_three(nums)
    squared = square_numbers(multiples)
    total = sum_numbers(squared)
    print("Total of squares of multiples of three:", total)
main()

