def calculate(a, b, op):
    if op == "+":
        return a + b
    elif op == "-":
        return a - b
    elif op == "*":
        return a * b
    elif op == "/":
        if b != 0:
            return a / b
        else:
            return None
def main():
    a = 10
    b = 5
    op = "*"
    result = calculate(a, b, op)
    print("Result:", result)
main()

